package io.cyntex.core.catalog;

import java.io.IOException;
import java.io.InputStream;
import java.io.UncheckedIOException;
import java.nio.charset.StandardCharsets;
import java.util.ArrayList;
import java.util.Collections;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.function.Function;

/**
 * Runtime access to the bundled connector catalog. The catalog is generated by the build tool and
 * shipped as static resources under {@code /catalog/} ({@code index.json} plus one
 * {@code <id>.json} per connector); this loads and reconstructs them with no reflection, so it is
 * free on a native image. Consumers (the wizard, validate, explain, completion) read entries here.
 */
public final class CyntexCatalog {

    private static final String INDEX = "/catalog/index.json";

    private final List<String> ids;
    private final Map<String, ConnectorCatalogEntry> byId;

    private CyntexCatalog(List<String> ids, Map<String, ConnectorCatalogEntry> byId) {
        this.ids = Collections.unmodifiableList(ids);
        this.byId = Collections.unmodifiableMap(byId);
    }

    /** Loads the bundled catalog once into an immutable instance. */
    public static CyntexCatalog load() {
        return build(indexIds(), id -> resource("/catalog/" + id + ".json"));
    }

    /**
     * Assembles a catalog from an index and an entry-JSON resolver. Rejects a duplicated id so a
     * corrupt index surfaces instead of silently overwriting an entry (which would leave
     * {@code ids()} and {@code all()} out of step). Package-private so it can be driven from a test.
     */
    static CyntexCatalog build(List<?> indexIds, Function<String, String> entryJson) {
        List<String> ids = new ArrayList<>();
        Map<String, ConnectorCatalogEntry> byId = new LinkedHashMap<>();
        for (Object idValue : indexIds) {
            String id = String.valueOf(idValue);
            if (byId.containsKey(id)) {
                throw new IllegalStateException("duplicate connector id in catalog index: " + id);
            }
            ids.add(id);
            byId.put(id, CatalogEntryReader.read(entryJson.apply(id)));
        }
        return new CyntexCatalog(ids, byId);
    }

    /**
     * Overlays server-registered rows on the bundled snapshot to form the online catalog view. A
     * registered entry shadows a bundled one with the same id (whole-row replace; identity is
     * id-only), and a registered-only id appends after the bundled ids in the given order. Used
     * only on the online (server) side — the offline path stays on {@link #load()} so it never
     * claims a connector it cannot run.
     */
    public static CyntexCatalog merged(CyntexCatalog bundled, List<ConnectorCatalogEntry> registered) {
        List<String> ids = new ArrayList<>(bundled.ids);
        Map<String, ConnectorCatalogEntry> byId = new LinkedHashMap<>(bundled.byId);
        for (ConnectorCatalogEntry entry : registered) {
            if (!byId.containsKey(entry.id())) {
                ids.add(entry.id());
            }
            byId.put(entry.id(), entry);
        }
        return new CyntexCatalog(ids, byId);
    }

    /** Connector ids in index (catalog) order. */
    public List<String> ids() {
        return ids;
    }

    /** All entries in index order. */
    public List<ConnectorCatalogEntry> all() {
        return new ArrayList<>(byId.values());
    }

    /** The entry for {@code id}, or throws if the catalog has no such connector. */
    public ConnectorCatalogEntry byId(String id) {
        ConnectorCatalogEntry entry = byId.get(id);
        if (entry == null) {
            throw new IllegalArgumentException("no connector '" + id + "' in catalog");
        }
        return entry;
    }

    private static List<?> indexIds() {
        Object parsed = CatalogJson.parse(resource(INDEX));
        if (!(parsed instanceof List<?> list)) {
            throw new IllegalStateException("catalog index is not a JSON array: " + INDEX);
        }
        return list;
    }

    private static String resource(String path) {
        try (InputStream in = CyntexCatalog.class.getResourceAsStream(path)) {
            if (in == null) {
                throw new IllegalStateException("bundled catalog resource missing: " + path);
            }
            return new String(in.readAllBytes(), StandardCharsets.UTF_8);
        } catch (IOException e) {
            throw new UncheckedIOException("reading catalog resource " + path, e);
        }
    }
}
